import{_ as s,o as a,c as t,ag as i}from"./chunks/framework.DXGyWiRo.js";const m=JSON.parse('{"title":"SQS vs SNS vs Kinesis","description":"https://campfirecode.medium.com/sqs-vs-sns-vs-kinesis-which-aws-messaging-service-to-use-1fa3aa6be97d","frontmatter":{"description":"https://campfirecode.medium.com/sqs-vs-sns-vs-kinesis-which-aws-messaging-service-to-use-1fa3aa6be97d"},"headers":[],"relativePath":"software-engineering/aws/sqs-vs-sns-vs-kinesis.md","filePath":"software-engineering/aws/sqs-vs-sns-vs-kinesis.md"}'),o={name:"software-engineering/aws/sqs-vs-sns-vs-kinesis.md"};function n(r,e,u,l,d,c){return a(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="sqs-vs-sns-vs-kinesis" tabindex="-1">SQS vs SNS vs Kinesis <a class="header-anchor" href="#sqs-vs-sns-vs-kinesis" aria-label="Permalink to &quot;SQS vs SNS vs Kinesis&quot;">​</a></h1><h2 id="sqs-vs-sns-vs-kinesis-which-aws-messaging-service-to-use" tabindex="-1">SQS vs SNS vs Kinesis which AWS messaging service to use <a href="#id-5c93" id="id-5c93"></a> <a class="header-anchor" href="#sqs-vs-sns-vs-kinesis-which-aws-messaging-service-to-use" aria-label="Permalink to &quot;SQS vs SNS vs Kinesis which AWS messaging service to use &lt;a href=&quot;#id-5c93&quot; id=&quot;id-5c93&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>AWS offers a number of messaging services for transferring data between different applications. Among the most used are Amazon SQS, Amazon SNS, and Amazon Kinesis Streams. All three are built to communicate and exchange information between applications, and each have pros and cons that make them particularly suited for certain situations.</p><h2 id="simple-queue-service-sqs" tabindex="-1">Simple Queue Service (SQS) <a href="#id-6947" id="id-6947"></a> <a class="header-anchor" href="#simple-queue-service-sqs" aria-label="Permalink to &quot;Simple Queue Service (SQS) &lt;a href=&quot;#id-6947&quot; id=&quot;id-6947&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p><strong>SQS</strong> is distributed <strong>queuing</strong> system. Messages are sent into a queue and receivers have to <strong>poll</strong> messages from SQS. Messages can only be received by a single receiver at a time, meaning that any one receiver can receive a message, process and delete it, but other receivers will not receive the same message later. A main use case for SQS is to decouple or integrate applications, allowing you to send data between the two with the guarantee that all messages get processed.</p><h3 id="when-to-use-sqs" tabindex="-1">When to use SQS: <a href="#id-4a43" id="id-4a43"></a> <a class="header-anchor" href="#when-to-use-sqs" aria-label="Permalink to &quot;When to use SQS: &lt;a href=&quot;#id-4a43&quot; id=&quot;id-4a43&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><ul><li>Your architecture requires asynchronous processing with guarantees that all tasks get processed</li><li>You need a durable and reliable queuing solution that will scale at low cost and require no management on your part</li></ul><h3 id="when-not-to-use-sqs" tabindex="-1">When not to use SQS: <a href="#id-4b17" id="id-4b17"></a> <a class="header-anchor" href="#when-not-to-use-sqs" aria-label="Permalink to &quot;When not to use SQS: &lt;a href=&quot;#id-4b17&quot; id=&quot;id-4b17&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><ul><li>You need to send messages to multiple receivers</li></ul><h2 id="simple-notification-service-sns" tabindex="-1">Simple Notification Service (SNS) <a href="#c77c" id="c77c"></a> <a class="header-anchor" href="#simple-notification-service-sns" aria-label="Permalink to &quot;Simple Notification Service (SNS) &lt;a href=&quot;#c77c&quot; id=&quot;c77c&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p><strong>SNS</strong> is a distributed <strong>publish-subscribe</strong> system. Unlike SQS where users have to <strong>poll</strong> messages from the queue, SNS messages are <strong>pushed</strong> to subscribers when they are sent by publishers to SNS. Amazon SNS delivers messages published to <em>topics</em> to one or more destinations. Using SNS topics, your publisher systems can fan out messages to a large number of subscriber endpoints for parallel processing, including <a href="https://aws.amazon.com/sqs/" target="_blank" rel="noreferrer">Amazon SQS</a> queues, <a href="https://aws.amazon.com/lambda/" target="_blank" rel="noreferrer">AWS Lambda</a> functions, and HTTP/S webhooks. SNS can also be used to fan out notifications to end users using mobile push, SMS, and email.</p><h3 id="when-to-use-sns" tabindex="-1">When to use SNS: <a href="#d808" id="d808"></a> <a class="header-anchor" href="#when-to-use-sns" aria-label="Permalink to &quot;When to use SNS: &lt;a href=&quot;#d808&quot; id=&quot;d808&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><ul><li>Your application requires delivering messages asynchronously to multiple consumers at a time but does not require strong delivery guarantees (if you need delivery guarantees you should use SQS queues)</li><li>You need to trigger asynchronous events across different parts of your application</li><li>You need to send mobile push notifications or SMS text messages</li><li>If you want unknown number and type of subscribers to receive messages</li></ul><h3 id="when-not-to-use-sns" tabindex="-1">When not to use SNS: <a href="#debc" id="debc"></a> <a class="header-anchor" href="#when-not-to-use-sns" aria-label="Permalink to &quot;When not to use SNS: &lt;a href=&quot;#debc&quot; id=&quot;debc&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><ul><li>You need strong delivery guarantees for messages</li><li>Your application sensitive to the latency associated with using AWS APIs via HTTP protocol and you have no need for specialized functions like SMS or mobile push</li></ul><h2 id="amazon-kinesis-streams" tabindex="-1">Amazon Kinesis Streams <a href="#id-6420" id="id-6420"></a> <a class="header-anchor" href="#amazon-kinesis-streams" aria-label="Permalink to &quot;Amazon Kinesis Streams &lt;a href=&quot;#id-6420&quot; id=&quot;id-6420&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p><a href="https://docs.aws.amazon.com/streams/latest/dev/introduction.html" target="_blank" rel="noreferrer">AWS Kinesis</a> is a managed data streaming service. Producers put data on a <em>stream</em> using Kinesis client library. Multiple different Kinesis data stream consumers can then process data from the stream concurrently. This is an important distinction from <em>queues</em> where only one kind of a consumer can take messages off the same queue. For example, one consumer can archive product order data while another analyzes data for fraud in real-time, and yet another one uses the data to dynamically update pricing and inventory data.</p><p>Another distinction from SQS is the ability to replay data. Once a message has been successfully processed, it <em>remains</em> on the stream. The message is not deleted.</p><p>Kinesis integrates well with other AWS services, including AWS Lambda. Kinesis can trigger Lambda functions in response to messages. Additionally, AWS services such as S3 or Dynamo can publish data to Kinesis streams.</p><h3 id="when-to-use-kinesis" tabindex="-1">When to use Kinesis: <a href="#e2b1" id="e2b1"></a> <a class="header-anchor" href="#when-to-use-kinesis" aria-label="Permalink to &quot;When to use Kinesis: &lt;a href=&quot;#e2b1&quot; id=&quot;e2b1&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><ul><li>Your architecture requires complex real-time processing of data streams</li><li>You have complex real-time analytics requirements</li><li>You need to trigger asynchronous events across different parts of your application</li></ul><h3 id="when-not-to-use-kinesis" tabindex="-1">When not to use Kinesis: <a href="#id-33ab" id="id-33ab"></a> <a class="header-anchor" href="#when-not-to-use-kinesis" aria-label="Permalink to &quot;When not to use Kinesis: &lt;a href=&quot;#id-33ab&quot; id=&quot;id-33ab&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><ul><li>You only need simple queues</li><li>You only need simple topics</li></ul><p>To summarize:</p><p><strong>SQS</strong>: messaging queue, sends data to one consumer at a time<br><strong>SNS</strong>: notification service, think email and SMS push notifications to multiple consumers<br><strong>Kinesis:</strong> data streaming service, built for complex real-time processing of data streams across multiple consumers</p><p>\\</p>',26)])])}const g=s(o,[["render",n]]);export{m as __pageData,g as default};
